import re
import os

file_path = '/home/alvin/pettyoffice/index.html'

with open(file_path, 'r', encoding='utf-8') as f:
    content = f.read()

# Replace fonts
content = content.replace(
    'https://fonts.googleapis.com/css2?family=Geist+Mono:wght@500;700&family=Geist:wght@400;500;600;700;800&display=swap',
    'https://fonts.googleapis.com/css2?family=EB+Garamond:wght@400;500;600;700&family=Lato:wght@300;400;700&display=swap'
)
content = content.replace("'Geist', system-ui, sans-serif", "'Lato', sans-serif")
content = content.replace("'Geist Mono', monospace", "'EB Garamond', serif")

# Replace class attributes for buttons and inputs
btn_primary_regex = r'w-full bg-neutral-950 text-white hover:bg-neutral-800 font-mono text-xs tracking-widest uppercase font-bold py-4 rounded-xl transition-all shadow-lg shadow-black/10 flex items-center justify-center(?: opacity-40 cursor-not-allowed)?'
content = re.sub(btn_primary_regex, 'btn-primary', content)

btn_secondary_regex = r'w-full bg-white border-2 border-neutral-200 hover:border-neutral-950 text-neutral-900 font-mono text-xs tracking-widest uppercase font-bold py-3 rounded-xl transition-all flex items-center justify-center'
content = re.sub(btn_secondary_regex, 'btn-secondary', content)

btn_secondary_small_regex = r'w-full bg-white border-2 border-neutral-200 hover:border-neutral-950 text-neutral-900 font-mono text-\[10px\] tracking-widest uppercase font-bold py-3 rounded-xl transition-all flex items-center justify-center'
content = re.sub(btn_secondary_small_regex, 'btn-secondary text-[10px]', content)

btn_primary_small_regex = r'w-full bg-neutral-950 text-white hover:bg-neutral-800 font-mono text-\[10px\] tracking-widest uppercase font-bold py-3 rounded-xl transition-all flex items-center justify-center'
content = re.sub(btn_primary_small_regex, 'btn-primary text-[10px]', content)

input_regex = r'w-full text-sm bg-white border-2 border-neutral-200 focus:border-neutral-950 outline-none rounded-xl p-3 text-neutral-900 transition placeholder:text-neutral-400'
content = re.sub(input_regex, 'input', content)

# Remove premium-glass and modify app-container
content = content.replace('premium-glass rounded-[40px] border border-white/60 shadow-tactile-raised', 'bg-[var(--color-background)] rounded-2xl border border-[var(--color-border)] shadow-xl')

# Modify mesh-bg CSS
mesh_bg_old = r'''.mesh-bg \{
            background-color: #FAF9F5;
            background-image:
                radial-gradient\(circle at 75% 20%, rgba\(245, 195, 175, 0\.6\) 0%, transparent 50%\),
                radial-gradient\(circle at 25% 40%, rgba\(235, 185, 215, 0\.5\) 0%, transparent 50%\),
                radial-gradient\(circle at 50% 70%, rgba\(210, 225, 245, 0\.6\) 0%, transparent 55%\);
            background-attachment: fixed;
        \}'''
mesh_bg_new = '''.mesh-bg {
            background-color: var(--color-background);
        }'''
content = re.sub(mesh_bg_old, mesh_bg_new, content)

